const registros = $input.first().json.registros || [];

const ahora = new Date();
const hoyStr = ahora.toLocaleDateString('es-CO', { timeZone: 'America/Bogota' });
const [hd, hm, hy] = hoyStr.split('/');
const hoy = new Date(+hy, +hm-1, +hd);

const diaSemana = hoy.getDay() === 0 ? 6 : hoy.getDay() - 1;
const lunes = new Date(hoy);
lunes.setDate(hoy.getDate() - diaSemana);
const domingo = new Date(lunes);
domingo.setDate(lunes.getDate() + 6);

const diasNombre = ['Dom','Lun','Mar','Mié','Jue','Vie','Sáb'];
const mesesNombre = ['ene','feb','mar','abr','may','jun','jul','ago','sep','oct','nov','dic'];

const deSemana = registros.filter(r => {
  const [d,m,y] = (r.fecha || '').split('/');
  if (!d || !m || !y) return false;
  const fecha = new Date(+y, +m-1, +d);
  return fecha >= lunes && fecha <= domingo;
});

const totalMetros = deSemana.reduce((s, r) => s + (r.metros || 0), 0);
const totalArchivos = deSemana.length;
const enviados = deSemana.filter(r => r.enviado).length;
const pendientes = totalArchivos - enviados;

// Por día
const porDia = {};
deSemana.forEach(r => {
  const [d,m,y] = r.fecha.split('/');
  const fecha = new Date(+y, +m-1, +d);
  if (!porDia[r.fecha]) porDia[r.fecha] = { metros: 0, archivos: 0, fecha };
  porDia[r.fecha].metros += r.metros || 0;
  porDia[r.fecha].archivos++;
});

const SEP = '\n';
const diasTexto = Object.entries(porDia)
  .sort((a,b) => a[1].fecha - b[1].fecha)
  .map(([fecha, d]) => {
    const nombre = diasNombre[d.fecha.getDay()];
    const dia = d.fecha.getDate();
    const mes = mesesNombre[d.fecha.getMonth()];
    return '  ' + nombre + ' ' + dia + ' ' + mes + ': ' + d.metros.toFixed(2) + ' m (' + d.archivos + ' PDF' + (d.archivos>1?'s':'') + ')';
  }).join(SEP);

// Día con más producción
let mejorDia = '';
if (Object.keys(porDia).length) {
  const top = Object.entries(porDia).sort((a,b) => b[1].metros - a[1].metros)[0];
  const [d,m,y] = top[0].split('/');
  const f = new Date(+y,+m-1,+d);
  mejorDia = SEP + '🏅 Mejor día: ' + diasNombre[f.getDay()] + ' ' + f.getDate() + ' ' + mesesNombre[f.getMonth()] + ' (' + top[1].metros.toFixed(2) + ' m)';
}

// Equipo más enviado
let masEnviado = '';
if (deSemana.length) {
  const porEquipo = {};
  deSemana.forEach(r => {
    if (!r.equipo) return;
    if (!porEquipo[r.equipo]) porEquipo[r.equipo] = 0;
    porEquipo[r.equipo] += r.metros || 0;
  });
  const top = Object.entries(porEquipo).sort((a,b) => b[1]-a[1])[0];
  if (top) masEnviado = SEP + '🏆 Más metros: ' + top[0] + ' (' + top[1].toFixed(2) + ' m)';
}

const fechaIni = lunes.getDate() + ' ' + mesesNombre[lunes.getMonth()];
const fechaFin = domingo.getDate() + ' ' + mesesNombre[domingo.getMonth()] + ' ' + domingo.getFullYear();
const encabezado = '🖨 *Reporte Semanal Calandra — W&S Textil*' + SEP + '📅 Semana ' + fechaIni + ' - ' + fechaFin;

const mensaje = totalArchivos === 0
  ? encabezado + SEP + SEP + 'Sin envíos registrados esta semana.'
  : encabezado +
    SEP + SEP +
    '📐 *Total metros:* ' + totalMetros.toFixed(2) + ' m' + SEP +
    '📁 *Total PDFs:* ' + totalArchivos + SEP +
    '✅ *Enviados:* ' + enviados + '  |  ⏳ *Pendientes:* ' + pendientes +
    SEP + SEP + '📅 *Por día:*' + SEP + (diasTexto || '  Sin datos') +
    mejorDia + masEnviado;

return [{ json: { mensaje } }];
